# BEST PRACTICE: Cascade Pattern with Adaptive Reranking
class CricketEvidenceRetriever:
    def retrieve_and_rerank(self, query: str, match_context: dict) -> list:
        # Stage 1: Fast filtering (batsman form check)
        batter_candidates = self.bm25_retriever.retrieve(
            query, top_k=50, field_weights={'recent_scores': 2.0}
        )

        # Stage 2: Dense retrieval (seasonal statistics)
        dense_candidates = self.dense_retriever.retrieve(
            query, top_k=20, context=match_context
        )

        # Merge and deduplicate
        merged = self._merge_candidates(batter_candidates, dense_candidates)

        # Stage 3: Conditional cross-encoder (only if uncertainty high)
        if self._query_uncertainty(query) > 0.6:
            reranked = self.cross_encoder.rerank(
                query, merged, top_k=10, batch_size=8
            )
        else:
            reranked = merged[:10]  # Skip expensive reranking

        return reranked

# ANTI-PATTERN: Eager Reranking Everything
class PoorRetriever:
    def retrieve_and_rerank(self, query: str) -> list:
        # Retrieves everything without filtering
        all_documents = self.vector_db.retrieve(query, top_k=500)

        # Applies expensive cross-encoder to entire set
        for doc in all_documents:  # ❌ Inefficient loop
            doc['score'] = self.cross_encoder.score(query, doc['text'])

        # Result: 45 second latency, blown token budget
        return sorted(all_documents, key=lambda x: x['score'])[:10]
